mapper.select:
SELECT * FROM ( SELECT p.post_id AS postId, a.account_id AS authorAccountId, d.nickname AS nickname, d.handle AS handle, a.role_type AS roleType, p.status AS status, TO_CHAR(p.created_at, 'YYYY-MM-DD HH24:MI:SS') AS createdAt, NVL(rpt.report_total, 0) AS reportTotalCount, NVL(rpt.pending_cnt, 0) AS reportPendingCount, ROW_NUMBER() OVER ( ORDER BY
p.created_at ASC p.created_at DESC
) AS rn FROM posts p LEFT JOIN ( SELECT r.target_id AS post_id, COUNT(*) AS report_total, SUM(CASE WHEN r.status = 0 THEN 1 ELSE 0 END) AS pending_cnt FROM reports r WHERE r.target_type = 'POST' GROUP BY r.target_id ) rpt ON rpt.post_id = p.post_id JOIN accounts a ON a.account_id = p.account_id JOIN vw_account_display d ON d.account_id = a.account_id
AND EXISTS ( SELECT 1 FROM reports r WHERE r.target_type = 'POST' AND r.target_id = p.post_id )
AND d.nickname LIKE '%' || #{nickname} || '%'
AND d.handle LIKE '%' || #{handle} || '%'
AND p.content LIKE '%' || #{content} || '%'
AND a.role_type = #{roleType}
AND p.status = #{status}
AND p.created_at >= TO_DATE(#{createdFrom}, 'YYYY-MM-DD')
AND p.created_at < TO_DATE(#{createdTo}, 'YYYY-MM-DD') + 1
) WHERE rn BETWEEN ((#{page} - 1) * #{size} + 1) AND (#{page} * #{size})
